import type { UmbCollectionRepository } from '@umbraco-cms/backoffice/collection';
import type { UmbControllerHost } from '@umbraco-cms/backoffice/controller-api';
import { FormsPrevalueSourceTypeCollectionServerDataSource } from './prevaluesource-type-collection.server.data-source.js';

export class FormsPrevalueSourceTypeCollectionRepository implements UmbCollectionRepository {
	#collectionSource: FormsPrevalueSourceTypeCollectionServerDataSource;

	constructor(host: UmbControllerHost) {
		this.#collectionSource = new FormsPrevalueSourceTypeCollectionServerDataSource(host);
	}

	async requestCollection() {
		return this.#collectionSource.getCollection();
	}

	destroy(): void {}
}

export default FormsPrevalueSourceTypeCollectionRepository;
