import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import type { UmbCollectionDataSource } from "@umbraco-cms/backoffice/collection";
import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import type { PreValueSourceTypeWithSettings } from "@umbraco-forms/generated";
import { PrevalueSourceTypeService } from "@umbraco-forms/generated";

export class FormsPrevalueSourceTypeCollectionServerDataSource
  implements UmbCollectionDataSource<PreValueSourceTypeWithSettings>
{
  #host: UmbControllerHost;

  constructor(host: UmbControllerHost) {
    this.#host = host;
  }

  async getCollection() {
    const { data, error } = await tryExecuteAndNotify(
      this.#host,
      PrevalueSourceTypeService.getPrevalueSourceType()
    );

    if (error) {
      return { error };
    }

    if (!data) {
      return { data: { items: [], total: 0 } };
    }

    return { data: { items: data, total: data.length } };
  }
}
